// Validate required parameters
const eventId = $json.query?.eventId || $json.query?.id || $json.body?.eventId || $json.body?.id;
const calendar = $json.query?.calendar || $json.body?.calendar || 'primary';

if (!eventId) {
  return [{
    json: {
      error: true,
      code: 'MISSING_EVENT_ID',
      message: 'Missing required parameter: eventId or id',
      example: '/webhook/get-event?eventId=your_event_id_here'
    }
  }];
}

return [{
  json: {
    eventId: eventId,
    calendar: calendar
  }
}];
